    TORCH_CHECK(weight.dtype() == at::kFloat, \"Only float32 supported\");
    TORCH_CHECK(x.sizes().size() == 4 && weight.sizes().size() == 4, \"Expect 4D tensors\");
    TORCH_CHECK(C == weight.size(0), \"Depthwise: out_channels must equal input channels\");
    TORCH_CHECK(weight.size(1) == 1, \"Depthwise weight must have in_channels/group = 1\");

    const int64_t outH = H - Kh + 1;
    const int64_t outW = W - Kw + 1;
    at::Tensor y = at::empty({N, C, outH, outW}, x.options());

    EXEC_NPU_CMD(aclnnConvDepthwise2dAsymmetricInputSquareKernelCustom, x, weight, y);
